from typing import List

class Solution:
    def minCost(self, nums: List[int], k: int) -> int:
        n = len(nums)
        # dp[i] is the minimum cost to split the first i elements
        dp = [float('inf')] * (n + 1)
        dp[0] = 0  # base case: cost of splitting 0 elements is 0

        for i in range(1, n + 1):
            # Try all possible subarrays ending at i-1
            for j in range(i):
                # current subarray is nums[j:i]
                # compute the importance value of this subarray
                # trimmed subarray: remove elements that appear only once
                freq = {}
                count_unique = 0
                for num in nums[j:i]:
                    if num in freq:
                        freq[num] += 1
                    else:
                        freq[num] = 1
                # Now compute the length of trimmed subarray
                trimmed_length = 0
                for num, cnt in freq.items():
                    if cnt > 1:
                        trimmed_length += cnt
                    else:
                        # if count is 1, we remove it
                        pass
                # importance value = k + trimmed_length
                cost = k + trimmed_length
                # dp[i] = min(dp[i], dp[j] + cost)
                dp[i] = min(dp[i], dp[j] + cost)

        return dp[n]
