class Solution:
    def maximumGood(self, statements: List[List[int]]) -> int:
        n = len(statements)
        max_good = 0

        # Try all possible subsets of people being good
        for mask in range(1 << n):
            good = [False] * n
            for i in range(n):
                if (mask >> i) & 1:
                    good[i] = True

            # Check if this subset is valid
            valid = True
            for i in range(n):
                if not good[i]:
                    continue  # Skip if person i is not good (they can lie)

                for j in range(n):
                    if i == j:
                        continue  # No statement about self

                    stmt = statements[i][j]
                    if stmt == 0:
                        # i says j is bad
                        if good[j]:
                            valid = False
                            break
                    elif stmt == 1:
                        # i says j is good
                        if not good[j]:
