class Solution:
    def longestRepeatingSubstring(self, s: str) -> int:
        n = len(s)
        if n == 0:
            return 0

        # Binary search on the possible length of the repeating substring
        def is_repeating(length):
            seen = set()
            for i in range(n - length + 1):
                substr = s[i:i+length]
                if substr in seen:
                    return True
                seen.add(substr)
            return False

        # Binary search boundaries
        left, right = 1, n
        answer = 0

        while left <= right:
            mid = (left + right) // 2
            if is_repeating(mid):
                answer = mid
                left = mid + 1
            else:
                right = mid - 1

        return answer
