class Solution:
    def longestSubstring(self, s: str, k: int) -> int:
        from collections import Counter

        def helper(s, k):
            # Count frequency of characters in the current string
            count = Counter(s)
            # Find the minimum frequency in the current string
            min_freq = min(count.values())
            # If all characters have frequency >= k, return the length of the string
            if min_freq >= k:
                return len(s)
            # Otherwise, split the string on the character with frequency < k
            # and recursively check the resulting substrings
            split_char = [char for char, freq in count.items() if freq < k][0]
            max_len = 0
            for substr in s.split(split_char):
                max_len = max(max_len, helper(substr, k))
            return max_len

        return helper(s, k)
