class Solution:
    def knightProbability(self, n: int, k: int, row: int, column: int) -> float:
        # Define the 8 possible knight moves
        directions = [(-2, -1), (-2, 1), (-1, -2), (-1, 2), (1, -2), (1, 2), (2, -1), (2, 1)]

        # Create a 3D DP table: dp[move][row][col] = probability
        dp = [[[0.0 for _ in range(n)] for _ in range(n)] for _ in range(k + 1)]

        # Base case: probability of being on the board after 0 moves is 1.0
        for i in range(n):
            for j in range(n):
                dp[0][i][j] = 1.0

        # Fill the DP table
        for move in range(1, k + 1):
            for i in range(n):
                for j in range(n):
                    for dx, dy in directions:
                        ni, nj = i + dx, j + dy
                        if 0 <= ni < n and 0 <= nj < n:
                            dp[move][i][j] += dp[move - 1][ni][nj] / 8.0

        # Sum the probabilities from the starting position after k moves
        total_prob = 0.0
        for i in range(n):
            for j in range(n):
                total_prob += dp[k][row][column]

        return total_prob
