from typing import List
from collections import deque

class Solution:
    def shortestDistance(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        buildings = []
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    buildings.append((i, j))

        # Directions: up, down, left, right
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        # For each building, perform BFS to calculate the total distance to all reachable empty lands
        # Also, track how many buildings each empty land can reach
        total_distance = [[0] * n for _ in range(m)]
        reachable_count = [[0] * n for _ in range(m)]

        for building in buildings:
            queue = deque()
            queue.append((building[0], building[1], 0))
            visited = [[False] * n for _ in range(m)]
            visited[building[0]][building[1]] = True

            while queue:
                x, y, dist = queue.popleft()
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny]:
                        if grid[nx][ny] == 0:
                            total_distance[nx][ny] += dist + 1
                            reachable_count[nx][ny] += 1
                            visited[nx][ny] = True
                            queue.append((nx, ny, dist + 1))
                        elif grid[nx][ny] == 1:
                            # Building, can't pass through
                            pass
                        else:
                            # Obstacle, can't pass through
                            pass

        # Find the empty land with the minimum total distance that can reach all buildings
        min_distance = float('inf')
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0 and reachable_count[i][j] == len(buildings):
                    min_distance = min(min_distance, total_distance[i][j])

        return min_distance if min_distance != float('inf') else -1
