class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        # Precompute the cost to convert a substring to a semi-palindrome
        n = len(s)
        # dp[i][j] will store the minimum changes needed to make s[i:j+1] a semi-palindrome
        dp = [[0] * n for _ in range(n)]

        # Function to calculate the cost to convert a substring s[i:j+1] into a semi-palindrome
        def min_changes_substring(s, i, j):
            length = j - i + 1
            min_cost = float('inf')
            # Try all possible divisors d of the length (excluding length itself)
            for d in range(1, length):
                if length % d != 0:
                    continue
                # For each divisor d, check all groups formed by d
                total_cost = 0
                for group_start in range(1, d + 1):
                    group_chars = []
                    for pos in range(group_start - 1, length, d):
                        group_chars.append(s[pos])
                    # Check if the group is a palindrome
                    # If not, calculate the minimum changes to make it a palindrome
                    cost = 0
                    left = 0
                    right = len(group_chars) - 1
                    while left < right:
                        if group_chars[left] != group_chars[right]:
                            cost += 1
                        left += 1
                        right -= 1
                    total_cost += cost
                min_cost = min(min_cost, total_cost)
            return min_cost

        # Fill the dp table
        for i in range(n):
            for j in range(i, n):
                dp[i][j] = min_changes_substring(s, i, j)

        # Now, we need to partition the string into k substrings such that the sum of changes is minimized
        # dp_partition[i][k] = min cost to partition s[0:i+1] into k substrings
        dp_partition = [[float('inf')] * (k + 1) for _ in range(n)]
        dp_partition[0][1] = dp[0][0]

        for i in range(n):
            for partitions in range(1, k + 1):
                if partitions == 1:
                    dp_partition[i][partitions] = dp[0][i]
                else:
                    for j in range(partitions - 1, i):
                        dp_partition[i][partitions] = min(dp_partition[i][partitions], dp_partition[j][partitions - 1] + dp[j + 1][i])

        return dp_partition[n - 1][k]

