from typing import List

class Solution:
    def equationsPossible(self, equations: List[str]) -> bool:
        # We need to check if all equations can be satisfied
        # First, process all the equality constraints to build connected components
        # Then, check if any of the inequality constraints are violated

        # Initialize parent array for Union-Find (Disjoint Set Union)
        parent = {}

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])  # Path compression
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                parent[root_x] = root_y

        # First, process all equality equations to build the Union-Find structure
        for eq in equations:
            if eq[1] == '=':
                a = eq[0]
                b = eq[3]
                if a not in parent:
                    parent[a] = a
                if b not in parent:
                    parent[b] = b
                union(a, b)

        # Now check all inequality equations
        for eq in equations:
            if eq[1] == '!':
                a = eq[0]
                b = eq[3]
                # If a and b are in the same connected component, the equation is violated
                if a in parent and b in parent and find(a) == find(b):
