class Solution:
    def smallestValue(self, n: int) -> int:
        def prime_factors(x):
            factors = []
            # Check for 2
            while x % 2 == 0:
                factors.append(2)
                x //= 2
            # Check for odd numbers up to sqrt(x)
            i = 3
            while i * i <= x:
                while x % i == 0:
                    factors.append(i)
                    x //= i
                i += 2
            if x > 1:
                factors.append(x)
            return factors

        def sum_factors(x):
            return sum(prime_factors(x))

        seen = set()
        while n not in seen:
            seen.add(n)
            factors = prime_factors(n)
            next_n = sum(factors)
            if next_n >= n:
                break  # No more improvement
            n = next_n

        return n
