class Solution:
    def encode(self, s: str) -> str:
        n = len(s)
        # dp[i][j] will store the shortest encoded string for s[i:j+1]
        dp = [["" for _ in range(n)] for _ in range(n)]

        # Fill the dp table for substrings of length 1
        for i in range(n):
            dp[i][i] = s[i]

        # Fill the dp table for substrings of length >= 2
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                # Initialize with the substring itself
                dp[i][j] = s[i:j+1]

                # Check for possible splits
                for k in range(i, j):
                    candidate = dp[i][k] + dp[k+1][j]
                    if len(candidate) < len(dp[i][j]):
                        dp[i][j] = candidate

                # Check for possible repetitions
                for period in range(1, (j - i + 1) // 2 + 1):
                    if (j - i + 1) % period == 0:
                        repeat = (j - i + 1) // period
                        pattern = dp[i][i + period - 1]
                        if pattern * repeat == s[i:j+1]:
                            encoded = f"{repeat}[{dp[i][i + period - 1]}]"
                            if len(encoded) < len(dp[i][j]):
                                dp[i][j] = encoded

        return dp[0][n-1]
