class Solution:
    def maxNumber(self, nums1: List[int], nums2: List[int], k: int) -> List[int]:
        def merge(a: List[int], b: List[int]) -> List[int]:
            merged = []
            i = j = 0
            while i < len(a) and j < len(b):
                if a[i] > b[j]:
                    merged.append(a[i])
                    i += 1
                elif a[i] < b[j]:
                    merged.append(b[j])
                    j += 1
                else:
                    # Tie-breaker: choose the one that leads to a larger sequence
                    # Compare the remaining sequences
                    if a[i:] + b[j:] > b[j:] + a[i:]:
                        merged.append(a[i])
                        i += 1
                    else:
                        merged.append(b[j])
                        j += 1
            merged += a[i:]
            merged += b[j:]
            return merged

        def max_subsequence(nums: List[int], k: int) -> List[int]:
            stack = []
            for i, num in enumerate(nums):
                while stack and stack[-1] < num and len(stack) + len(nums) - i > k:
                    stack.pop()
                if len(stack) < k:
                    stack.append(num)
            return stack

        max_result = []
        m, n = len(nums1), len(nums2)
        for i in range(k + 1):
            if i > m or k - i > n:
                continue
            sub1 = max_subsequence(nums1, i)
            sub2 = max_subsequence(nums2, k - i)
            merged = merge(sub1, sub2)
            if merged > max_result:
                max_result = merged
        return max_result
