class Solution:
    def minMutation(self, startGene: str, endGene: str, bank: List[str]) -> int:
        from collections import deque

        bank = set(bank)
        if endGene not in bank and endGene != startGene:
            return -1

        queue = deque()
        queue.append((startGene, 0))
        visited = set()
        visited.add(startGene)

        chars = ['A', 'C', 'G', 'T']

        while queue:
            gene, steps = queue.popleft()
            if gene == endGene:
                return steps

            for i in range(8):
                for c in chars:
                    if c != gene[i]:
                        next_gene = gene[:i] + c + gene[i+1:]
                        if next_gene in bank or next_gene == endGene:
                            if next_gene not in visited:
                                visited.add(next_gene)
                                queue.append((next_gene, steps + 1))

        return -1
