from typing import List

class Solution:
    def countCornerRectangles(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        count = 0

        # Iterate over all pairs of rows
        for i in range(m):
            # Get the positions of 1s in the current row
            ones_in_row_i = [j for j in range(n) if grid[i][j] == 1]
            # For each pair of columns in the current row, check if both columns have 1s in subsequent rows
            for j in range(len(ones_in_row_i)):
                for k in range(j + 1, len(ones_in_row_i)):
                    col1, col2 = ones_in_row_i[j], ones_in_row_i[k]
                    # Count how many rows below the current row have 1s in both columns
                    for r in range(i + 1, m):
                        if grid[r][col1] == 1 and grid[r][col2] == 1:
                            count += 1
        return count
