class Solution:
    def isNumber(self, s: str) -> bool:
        # Check if the string is a valid number according to the problem's definition
        # A valid number can be an integer or a decimal number, optionally followed by an exponent

        # Split the string into parts before and after the exponent
        if 'e' in s or 'E' in s:
            parts = s.lower().split('e')
            if len(parts) != 2:
                return False
            # Check if the exponent part is a valid integer
            if not self.isInteger(parts[1]):
                return False
            # Check if the base part is a valid decimal or integer
            return self.isDecimal(parts[0]) or self.isInteger(parts[0])

        # If no exponent, check if it's a valid decimal or integer
        return self.isDecimal(s) or self.isInteger(s)

    def isInteger(self, s: str) -> bool:
        # Check if the string is a valid integer
        # Optional sign followed by one or more digits
        if not s:
            return False
        if s[0] in '+-':
            s = s[1:]
        return s.isdigit() and len(s) > 0

    def isDecimal(self, s: str) -> bool:
        # Check if the string is a valid decimal number
        # One of the following forms:
        # 1. Digits followed by a dot
        # 2. Digits followed by a dot followed by digits
        # 3. A dot followed by digits
        if not s:
            return False
        if s[0] in '+-':
            s = s[1:]

        # Split the string into parts before and after the dot
        if '.' in s:
            parts = s.split('.')
            if len(parts) != 2:
                return False
            # Check if the parts are valid
            if not parts[0] and not parts[1]:
                return False
            if parts[0] and not parts[0].isdigit():
                return False
            if parts[1] and not parts[1].isdigit():
                return False
            return True
        else:
            # If there is no dot, it's not a decimal number
            return False
