class Solution:
    def findTargetSumWays(self, nums: List[int], target: int) -> int:
        total = sum(nums)
        if target > total or (total - target) % 2 != 0:
            return 0

        target_sub = (total - target) // 2
        if target_sub < 0:
            return 0

        dp = [0] * (target_sub + 1)
        dp[0] = 1

        for num in nums:
            for i in range(target_sub, num - 1, -1):
                dp[i] += dp[i - num]

        return dp[target_sub]
