class Solution:
    def maxJumps(self, arr: List[int], d: int) -> int:
        n = len(arr)
        # Memoization cache: dp[i] will store the maximum number of indices that can be visited starting from index i
        dp = [-1] * n

        def dfs(i):
            if dp[i] != -1:
                return dp[i]
            max_visits = 1  # At least the starting index itself

            # Try to jump to the right
            for j in range(i + 1, min(i + d + 1, n)):
                if arr[i] <= arr[j]:
                    break
                # Check if all elements between i and j are less than arr[i]
                valid = True
                for k in range(i + 1, j):
                    if arr[k] >= arr[i]:
                        valid = False
                        break
                if valid:
                    max_visits = max(max_visits, 1 + dfs(j))

            # Try to jump to the left
            for j in range(i - 1, max(-1, i - d - 1), -1):
                if arr[i] <= arr[j]:
                    break
                # Check if all elements between j and i are less than arr[i]
                valid = True
                for k in range(j + 1, i):
                    if arr[k] >= arr[i]:
                        valid = False
                        break
                if valid:
                    max_visits = max(max_visits, 1 + dfs(j))

            dp[i] = max_visits
            return max_visits

        # Compute the maximum over all starting indices
        return max(dfs(i) for i in range(n))
