class Solution:
    def smallestBeautifulString(self, s: str, k: int) -> str:
        n = len(s)
        s_list = list(s)
        alphabet = [chr(ord('a') + i) for i in range(k)]

        def is_beautiful(string):
            for i in range(len(string) - 1):
                for j in range(i + 1, len(string)):
                    if string[i] == string[j]:
                        return False
            for i in range(len(string) - 1):
                if string[i] == string[i + 1]:
                    return False
            return True

        # Try to increment the string lexicographically
        for i in range(n - 1, -1, -1):
            # Try to increase the character at position i
            for c in alphabet:
                if c <= s_list[i]:
                    continue
                # Try to replace s_list[i] with c
                s_list[i] = c
                # Now check if the rest of the string can be filled with characters that make it beautiful
                # We need to ensure that no two adjacent characters are the same and no palindromic substring of length >=2
                # We will greedily build the rest of the string
                valid = True
                for j in range(i + 1, n):
                    for ch in alphabet:
                        if ch == s_list[j - 1] or ch == s_list[j - 2]:
                            continue
                        s_list[j] = ch
                        break
                    else:
                        valid = False
                        break
                if valid:
                    # Now check if the entire string is beautiful
                    if is_beautiful(s_list):
                        return ''.join(s_list)
                # Backtrack
                s_list[i] = s_list[i - 1] if i > 0 else s_list[i]
        return ""
