class Solution:
    def maximumTripletValue(self, nums: List[int]) -> int:
        max_val = 0
        n = len(nums)

        # Precompute max(nums[i] - nums[j]) for i < j
        max_diff = [-float('inf')] * n
        for j in range(1, n):
            for i in range(j):
                max_diff[j] = max(max_diff[j], nums[i] - nums[j])

        # Now find the maximum (max_diff[j] * nums[k]) for k > j
        for j in range(n - 1):
            for k in range(j + 1, n):
                current = max_diff[j] * nums[k]
                if current > max_val:
                    max_val = current

        return max_val if max_val > 0 else 0
