class Solution:
    def minDays(self, grid: List[List[int]]) -> int:
        from collections import deque

        def is_connected():
            visited = [[False] * len(grid[0]) for _ in range(len(grid))]
            queue = deque()
            count = 0
            for i in range(len(grid)):
                for j in range(len(grid[0])):
                    if grid[i][j] == 1:
                        count += 1
                        queue.append((i, j))
                        visited[i][j] = True
                        break
                if count > 0:
                    break

            if count == 0:
                return False

            directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
            while queue:
                x, y = queue.popleft()
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < len(grid) and 0 <= ny < len(grid[0]) and not visited[nx][ny] and grid[nx][ny] == 1:
                        visited[nx][ny] = True
                        queue.append((nx, ny))
            connected = True
            for i in range(len(grid)):
                for j in range(len(grid[0])):
                    if grid[i][j] == 1 and not visited[i][j]:
                        connected = False
                        break
                if not connected:
                    break
            return connected

        if not is_connected():
            return 0

        m, n = len(grid), len(grid[0])
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    grid[i][j] = 0
                    if not is_connected():
                        return 1
                    grid[i][j] = 1

        return 2
