from typing import List
from collections import deque
import copy

class Solution:
    def shortestDistance(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        buildings = []
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        # Collect all buildings
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    buildings.append((i, j))

        # For each empty land, calculate the total distance to all buildings
        # and check if it's reachable from all buildings
        total_distances = [[0] * n for _ in range(m)]
        reachable = [[0] * n for _ in range(m)]

        for building in buildings:
            i, j = building
            queue = deque([(i, j)])
            visited = [[False] * n for _ in range(m)]
            visited[i][j] = True
            distance = 0

            while queue:
                x, y = queue.popleft()
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny]:
                        if grid[nx][ny] == 0:
                            total_distances[nx][ny] += distance + 1
                            reachable[nx][ny] += 1
                            visited[nx][ny] = True
                            queue.append((nx, ny))
                        elif grid[nx][ny] == 1:
                            # If there's another building, we can't reach all buildings from this land
                            return -1
            # If any empty land is not reachable from this building, return -1
            if any(not visited[i][j] for i in range(m) for j in range(n) if grid[i][j] == 0):
                return -1

        # Find the empty land with minimum total distance that is reachable from all buildings
        min_distance = float('inf')
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0 and reachable[i][j] == len(buildings):
                    min_distance = min(min_distance, total_distances[i][j])

        return min_distance if min_distance != float('inf') else -1
