class Solution:
    def equalizeWater(self, buckets: List[int], loss: int) -> float:
        left = 0
        right = max(buckets)

        def can_equalize(target):
            total_transfer = 0
            for b in buckets:
                if b > target:
                    transfer = b - target
                    total_transfer += transfer * (1 - loss / 100)
                elif b < target:
                    total_transfer -= target - b
            return total_transfer >= 0

        # Use binary search to find the maximum possible target
        while left < right:
            mid = (left + right + 1) / 2
            if can_equalize(mid):
                left = mid
            else:
                right = mid - 1

        return round(left, 5)
