class Solution:
    def maximumTastiness(self, price: List[int], k: int) -> int:
        price.sort()
        left, right = 0, price[-1] - price[0]

        def is_possible(min_diff):
            count = 1
            last = price[0]
            for p in price[1:]:
                if p - last >= min_diff:
                    count += 1
                    last = p
                    if count >= k:
                        return True
            return count >= k

        while left < right:
            mid = (left + right + 1) // 2
            if is_possible(mid):
                left = mid
            else:
                right = mid - 1
        return left
