class Solution:
    def concatenatedBinary(self, n: int) -> int:
        MOD = 10**9 + 7
        result = 0
        length = 0
        for i in range(1, n + 1):
            # Determine the number of bits needed to represent i
            if i == 0:
                length = 0
            elif i == 1:
                length = 1
            else:
                length = length + 1 if (i & (i - 1)) == 0 else length

            # Shift the current result left by the number of bits and add the current number
            result = (result << length) | i
            result %= MOD

        return result
