import functools
import math

class Solution:
    def soupServings(self, n: int) -> float:
        # Convert n to the nearest multiple of 25, since all operations are in multiples of 25
        # This is to reduce the state space and avoid dealing with very large n
        n = math.ceil(n / 25) * 25
        # Use memoization to cache results of subproblems
        @functools.lru_cache(None)
        def dp(a, b):
            # Base cases
            if a <= 0 and b <= 0:
                return 0.5  # Both empty at the same time
            if a <= 0:
                return 1.0  # A is empty first
            if b <= 0:
                return 0.0  # B is empty first
            # Recursive case: try all four operations
            return 0.25 * (dp(a - 100, b - 0) + dp(a - 75, b - 25) + dp(a - 50, b - 50) + dp(a - 25, b - 75))

        # If n is very large, the probability approaches 1.0
        # This is due to the fact that the probability converges to 1.0 for large n
        # We can use a threshold to avoid unnecessary computation
        if n >= 4800:
            return 1.0
        return dp(n, n)

