class Solution:
    def smallestSubsequence(self, s: str) -> str:
        stack = []
        seen = set()
        last_occurrence = {}

        # Preprocess the last occurrence of each character
        for i, char in enumerate(s):
            last_occurrence[char] = i

        for i, char in enumerate(s):
            # If the character is already in the stack, skip it
            if char in seen:
                continue

            # Remove characters from the stack that are larger than current char
            # and appear later in the string (so they can be added later)
            while stack and char < stack[-1] and last_occurrence[stack[-1]] > i:
                removed = stack.pop()
                seen.remove(removed)

            stack.append(char)
            seen.add(char)

        return ''.join(stack)

