class Solution:
    def convert(self, s: str, numRows: int) -> str:
        if numRows == 1 or numRows >= len(s):
            return s

        rows = [''] * numRows
        current_row = 0
        direction = 1  # 1 for down, -1 for up

        for char in s:
            rows[current_row] += char
            if current_row == numRows - 1:
                direction = -1
            elif current_row == 0:
                direction = 1
            current_row += direction

        return ''.join(rows)
