class Solution:
    def findSubstringInWraproundString(self, s: str) -> int:
        # We need to count all unique substrings of s that are present in the infinite base string.
        # The base string is the infinite wraparound of "abcdefghijklmnopqrstuvwxyz".
        # A substring of s is valid if it is a sequence of consecutive characters in the base string.
        # That is, the substring must be a sequence where each character follows the previous one in the alphabet (with wraparound).

        # We can approach this problem by tracking the maximum length of valid sequences ending at each character.
        # For example, if the substring "zab" is valid, then for 'b', the maximum length of valid sequence ending at 'b' is 3.
        # This helps us avoid counting duplicates and ensures we count all unique substrings.

        # We'll use a dictionary to store the maximum length of valid sequences ending at each character.
        max_len = {}
        current_len = 0

        for i in range(len(s)):
            # Check if current character continues the sequence
            if i == 0 or (ord(s[i]) - ord(s[i-1]) == 1 or (s[i-1] == 'z' and s[i] == 'a')):
                current_len += 1
            else:
                current_len = 1

            # Update the maximum length for the current character
            if s[i] not in max_len or current_len > max_len[s[i]]:
                max_len[s[i]] = current_len

        # The total number of unique valid substrings is the sum of the maximum lengths for each character
        return sum(max_len.values())
