class Solution:
    def singleNumber(self, nums: List[int]) -> int:
        # Initialize result to 0
        result = 0

        # Iterate through each bit position (0 to 31)
        for i in range(32):
            # Count the number of elements that have the ith bit set
            count = 0
            for num in nums:
                # Handle negative numbers using two's complement
                if i < 31:
                    bit = (num >> i) & 1
                else:
                    # For the 32nd bit, check if the number is negative
                    # In Python, negative numbers are represented with an infinite number of leading 1s
                    # So we need to check if the number is negative before shifting
                    if num < 0:
                        bit = 1
                    else:
                        bit = (num >> i) & 1
                count += bit

            # If the count is not a multiple of 3, set the ith bit in the result
            if count % 3 != 0:
                if i == 31:
                    # If the result's 32nd bit is set, it means the number is negative
                    result -= (1 << 31)
                else:
                    result |= (1 << i)

        return result
