from typing import List

class Solution:
    def waysToMakeFair(self, nums: List[int]) -> int:
        # Calculate the total sum of even and odd indexed elements
        total_even = 0
        total_odd = 0
        for i, num in enumerate(nums):
            if i % 2 == 0:
                total_even += num
            else:
                total_odd += num

        count = 0
        # Iterate through each index and simulate its removal
        for i in range(len(nums)):
            # Calculate the new even and odd sums after removing index i
            new_even = 0
            new_odd = 0
            even_sum = 0
            odd_sum = 0
            for j in range(len(nums)):
                if j == i:
                    continue
                if j % 2 == 0:
                    even_sum += nums[j]
                else:
                    odd_sum += nums[j]

            # Adjust the parity of the indices after the removed index
            # The parity flips for all elements after the removed index
            # So we need to re-calculate the sums with adjusted parity
            # Re-calculate even and odd sums with the current index removed
            # and parity adjusted
            new_even_sum = 0
            new_odd_sum = 0
            for j in range(len(nums)):
                if j == i:
                    continue
                if j < i:
                    # parity remains the same
                    if j % 2 == 0:
                        new_even_sum += nums[j]
                    else:
                        new_odd_sum += nums[j]
                else:
                    # parity flips
                    if j % 2 == 0:
                        new_odd_sum += nums[j]
                    else:
                        new_even_sum += nums[j]

            if new_even_sum == new_odd_sum:
                count += 1

        return count
