from typing import List
import itertools
import math

class Solution:
    def maxSumTwoNoOverlap(self, nums: List[int], firstLen: int, secondLen: int) -> int:
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        def get_max_sum(arr, l):
            max_sum = -math.inf
            for i in range(len(arr) - l + 1):
                current_sum = prefix[i + l] - prefix[i]
                if current_sum > max_sum:
                    max_sum = current_sum
            return max_sum

        max_total = -math.inf

        # Case 1: firstLen subarray comes before secondLen subarray
        for i in range(n - firstLen + 1):
            first_sum = prefix[i + firstLen] - prefix[i]
            # Find max secondLen subarray after i + firstLen
            max_second = -math.inf
            for j in range(i + firstLen, n - secondLen + 1):
                second_sum = prefix[j + secondLen] - prefix[j]
                if second_sum > max_second:
                    max_second = second_sum
            if max_second != -math.inf:
                max_total = max(max_total, first_sum + max_second)

        # Case 2: secondLen subarray comes before firstLen subarray
        for i in range(n - secondLen + 1):
            second_sum = prefix[i + secondLen] - prefix[i]
            # Find max firstLen subarray after i + secondLen
            max_first = -math.inf
            for j in range(i + secondLen, n - firstLen + 1):
                first_sum = prefix[j + firstLen] - prefix[j]
                if first_sum > max_first:
                    max_first = first_sum
            if max_first != -math.inf:
                max_total = max(max_total, second_sum + max_first)

        return max_total
