class Solution:
    def punishmentNumber(self, n: int) -> int:
        def is_valid(i):
            square = str(i * i)
            # Helper function to check if the square can be partitioned into substrings that sum to i
            def can_partition(s, target, start):
                if start == len(s):
                    return target == 0
                for end in range(start + 1, len(s) + 1):
                    current = s[start:end]
                    if current[0] == '0' and len(current) > 1:
                        continue  # Skip leading zeros
                    num = int(current)
                    if can_partition(s, target - num, end):
                        return True
                return False

            return can_partition(square, i, 0)

        # Calculate the sum of squares of all valid i in [1, n]
        result = 0
        for i in range(1, n + 1):
            if is_valid(i):
                result += i * i
        return result

