from typing import List

class Solution:
    def validateBinaryTreeNodes(self, n: int, leftChild: List[int], rightChild: List[int]) -> bool:
        # Step 1: Check for duplicate children (each node can have at most one parent)
        parent_count = [0] * n
        for i in range(n):
            left = leftChild[i]
            right = rightChild[i]
            if left != -1:
                if parent_count[left] > 0:
                    return False
                parent_count[left] += 1
            if right != -1:
                if parent_count[right] > 0:
                    return False
                parent_count[right] += 1

        # Step 2: Check for exactly one root (node with no parent)
        root_count = 0
        for i in range(n):
            if parent_count[i] == 0:
                root_count += 1
                if root_count > 1:
                    return False

        # Step 3: Check for cycles and ensure all nodes are reachable from the root
        visited = [False] * n
        # Find the root
        root = -1
        for i in range(n):
            if parent_count[i] == 0:
                root = i
                break

        # BFS to traverse the tree
        queue = [root]
        visited[root] = True
        while queue:
            node = queue.pop(0)
            for child in [leftChild[node], rightChild[node]]:
                if child != -1:
                    if visited[child]:
                        return False
                    visited[child] = True
                    queue.append(child)

        # Step 4: Ensure all nodes are visited (i.e., the tree is connected)
        for i in range(n):
            if not visited[i]:
                return False

        return True
