class Solution:
    def findAnagrams(self, s: str, p: str) -> List[int]:
        from collections import Counter

        p_count = Counter(p)
        s_count = Counter()
        result = []
        window_size = len(p)

        for i, char in enumerate(s):
            s_count[char] += 1

            if i >= window_size:
                left_char = s[i - window_size]
                s_count[left_char] -= 1
                if s_count[left_char] == 0:
                    del s_count[left_char]

            if s_count == p_count:
                result.append(i - window_size + 1)

        return result
