class Solution:
    def smallestBeautifulString(self, s: str, k: int) -> str:
        n = len(s)
        s_list = list(s)
        chars = [chr(ord('a') + i) for i in range(k)]

        def is_beautiful(string):
            for i in range(len(string) - 1):
                if string[i] == string[i+1]:
                    return False
                if i >= 1 and string[i-1] == string[i+1]:
                    return False
            return True

        # Try to increment the string lexicographically
        for i in range(n-1, -1, -1):
            # Find the next character
            for c in chars:
                if c == s_list[i]:
                    continue
                # Try to replace s_list[i] with c
                s_list[i] = c
                # Check if the rest can be filled to make a beautiful string
                # We need to fill the rest of the string with characters that don't form palindromes
                # Start from i+1
                temp = s_list[:i] + [c]
                valid = True
                for j in range(i+1, n):
                    for ch in chars:
                        if ch == temp[-1] or ch == temp[-2] or ch == temp[j-2] if j >= 2 else ch == temp[-1]:
                            continue
                        temp.append(ch)
                        break
                    else:
                        valid = False
                        break
                if valid:
                    if is_beautiful(temp):
                        return ''.join(temp)
                # Backtrack
                s_list[i] = s_list[i-1] if i > 0 else ''
        return ""
