from typing import List
import math

class Solution:
    def primeSubOperation(self, nums: List[int]) -> bool:
        def is_prime(n):
            if n < 2:
                return False
            for i in range(2, int(math.sqrt(n)) + 1):
                if n % i == 0:
                    return False
            return True

        def get_primes_less_than(n):
            primes = []
            for i in range(2, n):
                if is_prime(i):
                    primes.append(i)
            return primes

        # We will process the array from right to left
        # To ensure that each number is strictly greater than the previous one
        # After the operation, nums[i] - p > nums[i-1]
        # So we want to find the largest prime p < nums[i] such that nums[i] - p > nums[i-1]
        # If such a prime exists, we subtract it from nums[i], otherwise return False

        prev = float('inf')
        for num in reversed(nums):
            # Find the largest prime p < num such that num - p > prev
            # So p < num - prev
            max_p = num - prev - 1
            if max_p <= 0:
                # No possible prime to subtract, so we can't make this number larger than prev
                return False
            # Find the largest prime less than max_p
            p = None
            for candidate in reversed(get_primes_less_than(max_p)):
                if candidate < max_p:
                    p = candidate
                    break
            if p is None:
                # No suitable prime found
                return False
            # Update prev to num - p
            prev = num - p
        return True
