class Solution:
    def largestSumOfAverages(self, nums: List[int], k: int) -> float:
        n = len(nums)
        # dp[i][j] represents the maximum score for the first i elements partitioned into j groups
        dp = [[0.0] * (k + 1) for _ in range(n + 1)]

        # Precompute prefix sums
        prefix_sum = [0] * (n + 1)
        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]

        # Fill the dp table
        for i in range(1, n + 1):
            for j in range(1, k + 1):
                # Try all possible previous partitions
                for m in range(j - 1, i):
                    # The current group is nums[m:i], and the previous groups are nums[0:m]
                    current_avg = (prefix_sum[i] - prefix_sum[m]) / (i - m)
                    dp[i][j] = max(dp[i][j], dp[m][j - 1] + current_avg)

        return dp[n][k]
