class Solution:
    def equalizeWater(self, buckets: List[int], loss: int) -> float:
        left = 0
        right = max(buckets)

        def can_equalize(mid):
            total_transfer = 0
            for b in buckets:
                if b > mid:
                    # Water to be poured out
                    transfer = b - mid
                    total_transfer += transfer * (1 - loss / 100)
                elif b < mid:
                    # Water to be received
                    transfer = mid - b
                    total_transfer -= transfer
                # If total_transfer is negative, it means we have more than enough water to transfer
                if total_transfer < 0:
                    return True
            return total_transfer >= 0

        # Binary search on the possible amount of water each bucket can have
        while left < right:
            mid = (left + right + 1) / 2
            if can_equalize(mid):
                left = mid
            else:
                right = mid - 1
        return round(left, 5)
