class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def is_stepping(num_str):
            if not num_str:
                return False
            for i in range(1, len(num_str)):
                if abs(int(num_str[i]) - int(num_str[i-1])) != 1:
                    return False
            return True

        def count_stepping_in_range(low_str, high_str):
            low_num = int(low_str)
            high_num = int(high_str)
            count = 0
            for num in range(low_num, high_num + 1):
                if is_stepping(str(num)):
                    count += 1
            return count

        return count_stepping_in_range(low, high) % MOD
