from typing import List

class Solution:
    def xorGame(self, nums: List[int]) -> bool:
        total_xor = 0
        for num in nums:
            total_xor ^= num

        if total_xor == 0:
            return True  # Alice wins immediately

        n = len(nums)
        if n % 2 == 0:
            return False  # Alice can't win if total_xor != 0 and n is even

        # If total_xor != 0 and n is odd, Alice can win if there exists a number that when removed,
        # makes the XOR of the remaining numbers equal to total_xor ^ num (which is the XOR of the rest)
        # So we check if any number in nums is equal to total_xor
        for num in nums:
            if num == total_xor:
                return True

        return False
