class Solution:
    def alienOrder(self, words: List[str]) -> str:
        # Build the graph
        graph = {}
        # Build the in-degree map
        in_degree = {}

        # Initialize the graph and in-degree for all unique characters
        for word in words:
            for char in word:
                if char not in graph:
                    graph[char] = []
                if char not in in_degree:
                    in_degree[char] = 0

        # Build the adjacency list based on the lexicographical order
        for i in range(len(words) - 1):
            word1 = words[i]
            word2 = words[i + 1]
            min_len = min(len(word1), len(word2))

            # Find the first differing character
            for j in range(min_len):
                char1 = word1[j]
                char2 = word2[j]
                if char1 != char2:
                    # Add an edge from char1 to char2
                    if char2 not in graph[char1]:
                        graph[char1].append(char2)
                        in_degree[char2] += 1
                    break

        # Topological sort using Kahn's algorithm
        queue = [char for char in in_degree if in_degree[char] == 0]
        result = []

        while queue:
            current = queue.pop(0)
            result.append(current)

            for neighbor in graph[current]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # Check if the result contains all unique characters
        if len(result) != len(in_degree):
            return ""

        return ''.join(result)
