from typing import List
from collections import deque

class Solution:
    def maximumInvitations(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        # For each boy, find the list of girls he can invite
        boys = [[] for _ in range(m)]
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    boys[i].append(j)

        # For each girl, keep track of the boy she is matched with
        girl_to_boy = [-1] * n

        # Function to find augmenting path using BFS for maximum matching
        def bpm(u, visited):
            for v in boys[u]:
                if not visited[v]:
                    visited[v] = True
                    if girl_to_boy[v] == -1 or bpm(girl_to_boy[v], visited):
                        girl_to_boy[v] = u
                        return True
            return False

        # Maximum bipartite matching
        max_matching = 0
        for u in range(m):
            visited = [False] * n
            if bpm(u, visited):
                max_matching += 1

        # Now, find the maximum number of disjoint pairs (each boy can invite one girl, each girl can accept one invitation)
        # This is the same as the maximum matching, but we can also consider the case where multiple pairs are formed
        # However, the maximum number of accepted invitations is equal to the size of the maximum matching
        return max_matching
