class Solution:
    def minimumSubarrayLength(self, nums: List[int], k: int) -> int:
        n = len(nums)
        min_len = float('inf')
        for i in range(n):
            or_val = 0
            for j in range(i, n):
                or_val |= nums[j]
                if or_val >= k:
                    min_len = min(min_len, j - i + 1)
                    break  # No need to extend further as we want the shortest
        return min_len if min_len != float('inf') else -1
