class Solution:
    def scoreOfParentheses(self, s: str) -> int:
        stack = []
        score = 0
        for char in s:
            if char == '(':
                stack.append(score)
                score = 0
            else:
                top = stack.pop()
                if top == 0:
                    score = 2 * score + 1
                else:
                    score = top + 2 * score
        return score
