class Solution:
    def judgePoint24(self, cards: List[int]) -> bool:
        from itertools import permutations, product
        from operator import add, sub, mul, truediv

        # Helper function to evaluate all possible expressions
        def dfs(nums):
            if len(nums) == 1:
                return abs(nums[0] - 24) < 1e-6

            # Try all pairs of numbers to combine
            for i in range(len(nums)):
                for j in range(len(nums)):
                    if i != j:
                        # Get the remaining numbers
                        remaining = [nums[k] for k in range(len(nums)) if k != i and k != j]
                        # Try all possible operations
                        for op in [add, sub, mul, truediv]:
                            if op == truediv and nums[j] == 0:
                                continue  # Avoid division by zero
                            new_val = op(nums[i], nums[j])
                            if dfs(remaining + [new_val]):
                                return True
            return False

        # Try all permutations of the input cards
        for perm in permutations(cards):
            if dfs(list(perm)):
                return True
        return False

